import { Component, EventEmitter, Input, Output } from '@angular/core';

@Component({
  selector: 'app-course-card',
  templateUrl: './course-card.component.html',
  styleUrls: ['./course-card.component.scss']
})
export class CourseCardComponent {
  @Input() isEditable: boolean = true;
  @Output() clickOnShow = new EventEmitter(); // create new clickOnShow event

  title: string = 'Sample title';
  description: string = 'Description sample';
  creationDate: Date = new Date();
  duration: number = 10;
  authors: string[] = ['Tsvetelin Naydenov', 'Rustam Levkovsky']

  onShowClick(){
    this.clickOnShow.emit(); // emit the event to the parent component
  }
}
